sql:
SELECT COUNT(DISTINCT mc.patient_id) AS active_patients
FROM medical_conditions mc
WHERE mc.status = 'active';

external_knowledge:
- 'active medical conditions' refers to conditions with a status of 'active';
- 'most frequently prescribed' means the medications that appear the most times in the active conditions;
- 'top 5' indicates the results are limited to the five highest occurrences.

sql:
SELECT patient_id, test_name, test_results_status
FROM lab_tests
ORDER BY test_name ASC;

SELECT medication_id, COUNT(*) AS change_count
FROM medication_changes
GROUP BY medication_id;
